// tolazyRecords converts a slice of CanonicalRecord to LazyRecord for use in
// filter tests. The raw line bytes are generated by marshaling the record so
// Decode() works correctly in tests that need full fields.
func toLazyRecords(recs []store.CanonicalRecord) []LazyRecord {
	out := make([]LazyRecord, 0, len(recs))
	for _, r := range recs {
		raw, _ := json.Marshal(r)
		out = append(out, LazyRecord{
			CanonicalID: r.CanonicalID,
			Revision:    r.Revision,
			Title:       r.Title,
			Kind:        r.Kind,
			Type:        r.Type,
			rawLine:     raw,
		})
	}
	return out
}

// sampleRecords returns a fixed set of records for filter tests.
func sampleRecords() []store.CanonicalRecord {
	return []store.CanonicalRecord{
		{CanonicalID: "a1", Title: "Fix auth bug", Kind: "observation", Type: "bugfix", Content: "auth token fix", Origin: store.Origin{Provider: "engram"}, SchemaVersion: 1},
		{CanonicalID: "a2", Title: "JWT decision", Kind: "observation", Type: "decision", Content: "use JWT for sessions", Origin: store.Origin{Provider: "engram"}, SchemaVersion: 1},
		{CanonicalID: "a3", Title: "Session end", Kind: "session_summary", Type: "learning", Content: "session wrapped up", Origin: store.Origin{Provider: "claude-mem"}, SchemaVersion: 1},
		{CanonicalID: "a4", Title: "Relation entry", Kind: "relation", Type: "architecture", Content: "depends on auth", Origin: store.Origin{Provider: "engram"}, SchemaVersion: 1},
	}
}

func sampleLazyRecords() []LazyRecord {
	return toLazyRecords(sampleRecords())
}

func TestFilterRecords_Substring_CaseInsensitive(t *testing.T) {
	records := sampleLazyRecords()

	t.Run("matches title", func(t *testing.T) {
		got := filterRecords(records, "auth", "", "")
		if len(got) != 1 {
			t.Errorf("want 1 result for 'auth' in title, got %d", len(got))
		}
	})

	t.Run("matches title jwt", func(t *testing.T) {
		got := filterRecords(records, "jwt", "", "")
		if len(got) != 1 {
			t.Errorf("want 1 result for 'jwt' in title, got %d", len(got))
		}
	})

	t.Run("case insensitive", func(t *testing.T) {
		got := filterRecords(records, "AUTH", "", "")
		if len(got) != 1 {
			t.Errorf("want 1 result for 'AUTH' (case-insensitive in title), got %d", len(got))
		}
	})

	t.Run("no match returns empty slice not nil", func(t *testing.T) {
		got := filterRecords(records, "zzznomatch", "", "")
		if got == nil {
			t.Error("want empty slice, got nil")
		}
		if len(got) != 0 {
			t.Errorf("want 0 results, got %d", len(got))
		}
	})
}

func TestFilterRecords_TypePrefix(t *testing.T) {
	records := sampleLazyRecords()

	got := filterRecords(records, "type:bugfix", "", "")
	if len(got) != 1 {
		t.Fatalf("want 1 result for type:bugfix, got %d", len(got))
	}
	if got[0].CanonicalID != "a1" {
		t.Errorf("want a1, got %s", got[0].CanonicalID)
	}
}

