func TestObsModel_SelectionMove(t *testing.T) {
	dir := t.TempDir()
	m := newObsModel(dir)
	m.SetSize(80, 24)

	m.all = sampleLazyRecords()
	m.applyFilter()

	if m.list.Index() != 0 {
		t.Errorf("want initial index 0, got %d", m.list.Index())
	}

	_, _ = m.Update(tea.KeyMsg{Type: tea.KeyDown})
	if m.list.Index() != 1 {
		t.Errorf("want index 1 after down, got %d", m.list.Index())
	}
}

func TestObsModel_ReloadCmd(t *testing.T) {
	dir := t.TempDir()
	m := newObsModel(dir)
	m.SetSize(80, 24)

	cmd := m.reloadCmd()
	msg := cmd()
	reload, ok := msg.(obsReloadMsg)
	if !ok {
		t.Fatalf("want obsReloadMsg, got %T", msg)
	}
	if reload.err != nil {
		t.Errorf("unexpected error: %v", reload.err)
	}
	// loadRecords on empty dir returns nil — that is valid.
	if len(reload.records) != 0 {
		t.Errorf("want 0 records for empty dir, got %d", len(reload.records))
	}
}

// TestObsModel_ReloadCmd_ReadsFromStoreSubdir is a regression test for the bug
// where the Observations tab showed nothing because reloadCmd read memory.jsonl
// from the project root instead of the .glia store subdirectory. The model
// carries the project root (subprocess --dir calls need it); file reads must
// resolve the .glia subdir themselves.
func TestObsModel_ReloadCmd_ReadsFromStoreSubdir(t *testing.T) {
	root := t.TempDir()
	storeDir := filepath.Join(root, ".glia")
	if err := os.MkdirAll(storeDir, 0o755); err != nil {
		t.Fatal(err)
	}
	rec := makeRecord("zz1", 1, false)
	writeJSONL(t, filepath.Join(storeDir, "memory.jsonl"), []any{rec})

	m := newObsModel(root)
	m.SetSize(80, 24)

	msg := m.reloadCmd()()
	reload, ok := msg.(obsReloadMsg)
	if !ok {
		t.Fatalf("want obsReloadMsg, got %T", msg)
	}
	if reload.err != nil {
		t.Fatalf("unexpected error: %v", reload.err)
	}
	if len(reload.records) != 1 {
		t.Fatalf("want 1 record loaded from .glia subdir, got %d", len(reload.records))
	}
	if reload.records[0].CanonicalID != "zz1" {
		t.Errorf("want zz1, got %s", reload.records[0].CanonicalID)
	}
}

func TestObsModel_FilterFocus(t *testing.T) {
	dir := t.TempDir()
	m := newObsModel(dir)
	m.SetSize(80, 24)
	m.all = sampleLazyRecords()
	m.applyFilter()

	next, _ := m.Update(tea.KeyMsg{Type: tea.KeyRunes, Runes: []rune{'/'}})
	obs, ok := next.(*obsModel)
	if !ok {
		t.Fatalf("want *obsModel, got %T", next)
	}
	if !obs.filterFocused {
		t.Error("want filter focused after /")
	}

	next2, _ := obs.Update(tea.KeyMsg{Type: tea.KeyEsc})
	obs2, ok := next2.(*obsModel)
	if !ok {
		t.Fatalf("want *obsModel, got %T", next2)
	}
	if obs2.filterFocused {
		t.Error("want filter unfocused after esc")
	}
}

func TestObsModel_FullScreenToggle(t *testing.T) {
	dir := t.TempDir()
	m := newObsModel(dir)
	m.SetSize(80, 24)
	m.all = sampleLazyRecords()
	m.applyFilter()

	next, _ := m.Update(tea.KeyMsg{Type: tea.KeyEnter})
	obs, ok := next.(*obsModel)
	if !ok {
		t.Fatalf("want *obsModel, got %T", next)
	}
	if !obs.fullScreen {
		t.Error("want fullScreen=true after enter")
	}

	next2, _ := obs.Update(tea.KeyMsg{Type: tea.KeyEsc})
	obs2, ok := next2.(*obsModel)
	if !ok {
		t.Fatalf("want *obsModel, got %T", next2)
	}
	if obs2.fullScreen {
		t.Error("want fullScreen=false after esc in full-screen")
	}
}

func TestObsModel_KindCycle(t *testing.T) {
	dir := t.TempDir()
	m := newObsModel(dir)
	m.SetSize(80, 24)
	m.all = sampleLazyRecords()
	m.applyFilter()

	next, _ := m.Update(tea.KeyMsg{Type: tea.KeyRunes, Runes: []rune{'f'}})
	obs, ok := next.(*obsModel)
	if !ok {
		t.Fatalf("want *obsModel, got %T", next)
	}
	if obs.filterKindIdx != 1 {
		t.Errorf("want filterKindIdx=1 after f, got %d", obs.filterKindIdx)
	}
	// observation kind: should filter to only observations (a1, a2).
	if len(obs.filtered) != 2 {
		t.Errorf("want 2 observations with kind filter, got %d", len(obs.filtered))
	}
}

